class Solution:
    def getHint(self, secret, guess):
        bulls = 0
        s_rest = []
        g_rest = []
        for a, b in zip(secret, guess):
            if a == b:
                bulls += 1
            else:
                s_rest.append(a)
                g_rest.append(b)
        cows = 0
        for d in '0123456789':
            cows += min(s_rest.count(d), g_rest.count(d))
        return str(bulls) + 'A' + str(cows) + 'B'

